import React, { useState } from 'react';
import { auditWebsite } from './services/api';

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@200;300;400;500;600;700&family=JetBrains+Mono:wght@300;400;500&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --purple:       #7c3aed;
    --purple-light: #a78bfa;
    --purple-dark:  #4f1d96;
    --cyan:         #0891b2;
    --cyan-light:   #22d3ee;
    --grad:         linear-gradient(135deg, #7c3aed, #0891b2);
    --text-dark:    #12062e;
    --text-mid:     #4b4878;
    --text-muted:   #7c78a8;
    --text-dim:     #b0adc8;
    --red:          #dc2626;
    --orange:       #ea580c;
    --green:        #059669;
    --radius:       12px;
    --radius-lg:    20px;
    --sans:         'Outfit', sans-serif;
    --mono:         'JetBrains Mono', monospace;
  }

  html { font-size: 15px; }

  body {
    background: #ffffff;
    color: var(--text-dark);
    font-family: var(--sans);
    min-height: 100vh;
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
    overflow-x: hidden;
  }

  /* ── Hero section (dark) ──────────────────────────────────────────── */
  .hero-wrapper {
    background: linear-gradient(160deg, #0a0718 0%, #1a0e40 45%, #0c1a3d 100%);
    padding: 0 28px 64px;
    position: relative;
    overflow: hidden;
  }

  .hero-wrapper::after {
    content: '';
    position: absolute;
    top: -200px; right: -200px;
    width: 600px; height: 600px;
    background: radial-gradient(circle, rgba(124,58,237,0.25) 0%, transparent 70%);
    pointer-events: none;
  }

  .hero-wrapper::before {
    content: '';
    position: absolute;
    bottom: -100px; left: -100px;
    width: 400px; height: 400px;
    background: radial-gradient(circle, rgba(8,145,178,0.2) 0%, transparent 70%);
    pointer-events: none;
  }

  /* ── Navbar ───────────────────────────────────────────────────────── */
  .navbar {
    display: flex; align-items: center; justify-content: space-between;
    padding: 28px 0 24px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
    margin-bottom: 64px;
    position: relative; z-index: 1;
  }

  .nav-logo {
    font-family: var(--sans);
    font-size: 1.25rem;
    font-weight: 700;
    color: #ffffff;
    letter-spacing: -0.02em;
  }

  .nav-logo .grad-text {
    background: var(--grad);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .nav-badge {
    font-family: var(--mono);
    font-size: 0.62rem;
    letter-spacing: 0.14em;
    text-transform: uppercase;
    color: rgba(255,255,255,0.45);
    padding: 7px 16px;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 100px;
    background: rgba(255,255,255,0.04);
  }

  /* ── Hero content ─────────────────────────────────────────────────── */
  .hero { margin-bottom: 48px; position: relative; z-index: 1; }

  .hero-eyebrow {
    font-family: var(--mono);
    font-size: 0.68rem;
    font-weight: 400;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--cyan-light);
    margin-bottom: 20px;
    display: flex; align-items: center; gap: 12px;
  }
  .hero-eyebrow::before {
    content: ''; display: block;
    width: 28px; height: 1px;
    background: var(--cyan-light);
    opacity: 0.6;
  }

  .hero h1 {
    font-size: clamp(2.6rem, 5vw, 3.8rem);
    font-weight: 300;
    line-height: 1.08;
    letter-spacing: -0.03em;
    color: #ffffff;
    margin-bottom: 20px;
  }

  .hero h1 strong {
    font-weight: 700;
    background: var(--grad);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  .hero-sub {
    font-size: 1rem;
    font-weight: 300;
    color: rgba(255,255,255,0.55);
    max-width: 540px;
    line-height: 1.75;
  }

  /* ── Input (inside dark hero) ─────────────────────────────────────── */
  .input-section { position: relative; z-index: 1; }

  .input-wrapper {
    display: flex; gap: 10px; align-items: center;
    background: rgba(255,255,255,0.07);
    border: 1px solid rgba(255,255,255,0.14);
    border-radius: var(--radius-lg);
    padding: 8px 8px 8px 22px;
    transition: border-color 0.25s, box-shadow 0.25s;
    backdrop-filter: blur(10px);
  }

  .input-wrapper:focus-within {
    border-color: rgba(124,58,237,0.55);
    box-shadow: 0 0 0 3px rgba(124,58,237,0.15);
  }

  .url-input {
    flex: 1; background: transparent; border: none;
    color: #ffffff;
    font-family: var(--mono); font-size: 0.83rem; font-weight: 300;
    outline: none; padding: 8px 0;
  }
  .url-input::placeholder { color: rgba(255,255,255,0.25); }

  .audit-btn {
    background: var(--grad);
    color: #fff; border: none;
    border-radius: 14px;
    padding: 14px 28px;
    font-family: var(--sans); font-size: 0.88rem; font-weight: 600;
    cursor: pointer;
    transition: opacity 0.15s, transform 0.1s;
    white-space: nowrap;
    letter-spacing: 0.01em;
  }
  .audit-btn:hover:not(:disabled) { opacity: 0.85; }
  .audit-btn:active:not(:disabled) { transform: scale(0.98); }
  .audit-btn:disabled { opacity: 0.35; cursor: not-allowed; }

  .error-msg {
    margin-top: 14px; padding: 13px 18px;
    background: rgba(220,38,38,0.08);
    border: 1px solid rgba(220,38,38,0.2);
    border-radius: var(--radius);
    color: #fca5a5; font-size: 0.82rem; font-family: var(--mono);
  }

  /* ── Page body (white) ────────────────────────────────────────────── */
  .page-body {
    max-width: 960px; margin: 0 auto;
    padding: 48px 28px 100px;
  }

  /* ── Loading ──────────────────────────────────────────────────────── */
  .loading {
    display: flex; align-items: center; gap: 14px;
    padding: 28px 0;
    color: var(--text-muted); font-family: var(--mono); font-size: 0.78rem;
  }
  .spinner {
    width: 20px; height: 20px;
    border: 2px solid #e9e6fb;
    border-top-color: var(--purple);
    border-radius: 50%;
    animation: spin 0.8s linear infinite; flex-shrink: 0;
  }
  @keyframes spin { to { transform: rotate(360deg); } }

  /* ── Audit meta bar ───────────────────────────────────────────────── */
  .audit-meta {
    display: flex; align-items: center; gap: 14px;
    padding: 14px 20px;
    background: linear-gradient(135deg, rgba(124,58,237,0.06), rgba(8,145,178,0.04));
    border: 1px solid rgba(124,58,237,0.15);
    border-radius: var(--radius);
    margin-bottom: 32px; flex-wrap: wrap;
  }
  .meta-dot {
    width: 8px; height: 8px; border-radius: 50%;
    background: var(--grad); flex-shrink: 0;
  }
  .meta-url {
    font-family: var(--mono); font-size: 0.78rem;
    color: var(--purple); flex: 1; min-width: 0;
    overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-weight: 400;
  }
  .meta-time { font-family: var(--mono); font-size: 0.7rem; color: var(--text-muted); }

  /* ── Section ──────────────────────────────────────────────────────── */
  .section {
    margin-bottom: 20px;
    border: 1px solid rgba(124,58,237,0.12);
    border-radius: var(--radius-lg);
    overflow: hidden;
    background: #ffffff;
    box-shadow: 0 2px 12px rgba(124,58,237,0.06);
  }

  .section-header {
    display: flex; align-items: center; justify-content: space-between;
    padding: 16px 22px;
    background: #faf9ff;
    border-bottom: 1px solid rgba(124,58,237,0.1);
    cursor: pointer; user-select: none;
    transition: background 0.15s;
  }
  .section-header:hover { background: #f3f0ff; }

  .section-title {
    font-family: var(--sans); font-size: 0.72rem; font-weight: 700;
    letter-spacing: 0.1em; text-transform: uppercase;
    color: var(--text-muted);
    display: flex; align-items: center; gap: 10px;
  }

  .s-dot { width: 6px; height: 6px; border-radius: 50%; flex-shrink: 0; background: var(--grad); }
  .s-dot.orange { background: linear-gradient(135deg, #ea580c, #c026d3); }
  .s-dot.green  { background: linear-gradient(135deg, #059669, #0891b2); }
  .s-dot.red    { background: linear-gradient(135deg, #dc2626, #ea580c); }

  .chevron { font-size: 0.62rem; color: var(--text-dim); transition: transform 0.2s; }
  .chevron.open { transform: rotate(180deg); }

  .section-body { padding: 22px; }

  /* ── Metrics ──────────────────────────────────────────────────────── */
  .metrics-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(148px, 1fr));
    gap: 10px;
  }

  .metric-card {
    background: #faf9ff;
    border: 1px solid rgba(124,58,237,0.1);
    border-radius: var(--radius);
    padding: 16px 14px;
    transition: border-color 0.2s, transform 0.15s, box-shadow 0.15s;
  }
  .metric-card:hover {
    border-color: rgba(124,58,237,0.25);
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(124,58,237,0.08);
  }

  .metric-value {
    font-family: var(--sans); font-size: 1.75rem; font-weight: 700;
    color: var(--text-dark); line-height: 1; margin-bottom: 8px;
    letter-spacing: -0.02em;
  }
  .metric-value.warn { color: var(--orange); }
  .metric-value.bad  { color: var(--red); }
  .metric-value.good { color: var(--green); }

  .metric-label {
    font-size: 0.66rem; color: var(--text-dim);
    text-transform: uppercase; letter-spacing: 0.08em; font-weight: 600;
  }

  .cta-pill {
    display: inline-block; font-family: var(--mono); font-size: 0.7rem;
    padding: 4px 12px;
    background: rgba(124,58,237,0.07);
    border: 1px solid rgba(124,58,237,0.18);
    border-radius: 100px; color: var(--purple);
  }

  .serp-box {
    margin-top: 18px; padding: 16px 18px;
    background: #faf9ff; border: 1px solid rgba(124,58,237,0.1);
    border-radius: var(--radius);
  }
  .serp-label {
    font-family: var(--mono); font-size: 0.62rem; color: var(--text-dim);
    letter-spacing: 0.1em; text-transform: uppercase; margin-bottom: 8px;
  }
  .serp-title { color: #1a73e8; font-size: 0.95rem; font-weight: 500; margin-bottom: 3px; }
  .serp-desc  { color: #4d5156; font-size: 0.8rem; line-height: 1.5; }

  /* ── Insights ─────────────────────────────────────────────────────── */
  .insights-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
  @media (max-width: 600px) { .insights-grid { grid-template-columns: 1fr; } }

  .insight-card {
    background: #faf9ff; border: 1px solid rgba(124,58,237,0.1);
    border-radius: var(--radius); padding: 18px;
    transition: border-color 0.2s, box-shadow 0.15s;
  }
  .insight-card:hover {
    border-color: rgba(124,58,237,0.22);
    box-shadow: 0 4px 12px rgba(124,58,237,0.06);
  }

  .insight-label {
    font-size: 0.63rem; font-weight: 700;
    letter-spacing: 0.12em; text-transform: uppercase; margin-bottom: 10px;
    background: var(--grad);
    -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;
  }
  .insight-card p { font-size: 0.875rem; color: var(--text-mid); line-height: 1.7; font-weight: 300; }

  /* ── Recommendations ──────────────────────────────────────────────── */
  .rec-list { display: flex; flex-direction: column; gap: 12px; }

  .rec-card {
    background: #faf9ff; border: 1px solid rgba(124,58,237,0.1);
    border-radius: var(--radius); padding: 18px 20px;
    display: grid; grid-template-columns: 44px 1fr;
    gap: 16px; align-items: start;
    transition: border-color 0.2s, transform 0.15s, box-shadow 0.15s;
  }
  .rec-card:hover {
    border-color: rgba(124,58,237,0.22);
    transform: translateX(3px);
    box-shadow: 0 4px 12px rgba(124,58,237,0.07);
  }

  .rec-num {
    width: 44px; height: 44px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-family: var(--sans); font-size: 0.78rem; font-weight: 700; flex-shrink: 0;
  }
  .rec-num.p1 { background: rgba(220,38,38,0.08);  color: var(--red);    border: 1px solid rgba(220,38,38,0.2);  }
  .rec-num.p2 { background: rgba(234,88,12,0.08);  color: var(--orange); border: 1px solid rgba(234,88,12,0.2);  }
  .rec-num.p3 { background: rgba(124,58,237,0.08); color: var(--purple); border: 1px solid rgba(124,58,237,0.2); }
  .rec-num.p4 { background: rgba(5,150,105,0.08);  color: var(--green);  border: 1px solid rgba(5,150,105,0.2);  }
  .rec-num.p5 { background: #f3f0ff; color: var(--text-muted); border: 1px solid rgba(124,58,237,0.12); }

  .rec-title    { font-size: 0.9rem; font-weight: 600; color: var(--text-dark); margin-bottom: 6px; }
  .rec-reasoning{ font-size: 0.83rem; color: var(--text-muted); line-height: 1.65; margin-bottom: 10px; font-weight: 300; }
  .rec-action   {
    font-size: 0.78rem; color: var(--cyan); font-family: var(--mono);
    padding: 10px 14px; background: rgba(8,145,178,0.06);
    border-radius: 8px; border-left: 2px solid var(--cyan); font-weight: 300;
  }

  /* ── Prompt logs ──────────────────────────────────────────────────── */
  .prompt-tabs {
    display: flex; gap: 2px; margin-bottom: 14px;
    background: #faf9ff; border-radius: var(--radius);
    padding: 4px; border: 1px solid rgba(124,58,237,0.1);
  }
  .prompt-tab {
    flex: 1; padding: 8px; border: none; background: transparent;
    color: var(--text-dim); font-family: var(--mono); font-size: 0.62rem;
    letter-spacing: 0.08em; text-transform: uppercase; cursor: pointer;
    border-radius: 8px; transition: all 0.15s;
  }
  .prompt-tab.active {
    background: #ffffff; color: var(--purple);
    border: 1px solid rgba(124,58,237,0.2);
    box-shadow: 0 1px 4px rgba(124,58,237,0.1);
  }

  .log-chips { display: flex; gap: 8px; margin-bottom: 14px; flex-wrap: wrap; }
  .log-chip {
    font-family: var(--mono); font-size: 0.68rem; color: var(--text-muted);
    padding: 5px 12px; background: #faf9ff;
    border: 1px solid rgba(124,58,237,0.12); border-radius: 100px;
  }
  .log-chip span { color: var(--purple); font-weight: 500; }

  .prompt-code {
    background: #faf9ff; border: 1px solid rgba(124,58,237,0.1);
    border-radius: var(--radius); padding: 16px;
    font-family: var(--mono); font-size: 0.74rem; font-weight: 300;
    color: var(--text-mid); white-space: pre-wrap; word-break: break-word;
    line-height: 1.8; max-height: 420px; overflow-y: auto;
  }
  .prompt-code::-webkit-scrollbar { width: 4px; }
  .prompt-code::-webkit-scrollbar-thumb { background: rgba(124,58,237,0.2); border-radius: 10px; }

  /* ── App wrapper ──────────────────────────────────────────────────── */
  .app-wrapper { min-height: 100vh; }
  .page-content { max-width: 960px; margin: 0 auto; padding: 48px 28px 100px; }
  .hero-inner   { max-width: 960px; margin: 0 auto; }
`;

function Section({ title, dotColor, children, defaultOpen = true }) {
  const [open, setOpen] = useState(defaultOpen);
  return (
    <div className="section">
      <div className="section-header" onClick={() => setOpen(!open)}>
        <div className="section-title">
          <span className={`s-dot ${dotColor || ''}`} />
          {title}
        </div>
        <span className={`chevron ${open ? 'open' : ''}`}>▼</span>
      </div>
      {open && <div className="section-body">{children}</div>}
    </div>
  );
}

function MetricCard({ label, value, colorClass }) {
  return (
    <div className="metric-card">
      <div className={`metric-value ${colorClass || ''}`}>{value ?? '—'}</div>
      <div className="metric-label">{label}</div>
    </div>
  );
}

function MetricsDisplay({ metrics }) {
  if (!metrics) return null;
  const altPct = metrics.missingAltPercent;
  const altColor = altPct > 50 ? 'bad' : altPct > 20 ? 'warn' : 'good';
  const h1Color = metrics.h1Count === 0 ? 'bad' : metrics.h1Count > 1 ? 'warn' : '';
  return (
    <Section title="Factual Metrics" defaultOpen={true}>
      <div className="metrics-grid">
        <MetricCard label="Word Count"       value={metrics.wordCount?.toLocaleString()} />
        <MetricCard label="H1 Tags"          value={metrics.h1Count}  colorClass={h1Color} />
        <MetricCard label="H2 Tags"          value={metrics.h2Count} />
        <MetricCard label="H3 Tags"          value={metrics.h3Count} />
        <MetricCard label="CTAs Found"       value={metrics.ctaCount} colorClass={metrics.ctaCount === 0 ? 'bad' : ''} />
        <MetricCard label="Internal Links"   value={metrics.internalLinks} />
        <MetricCard label="External Links"   value={metrics.externalLinks} />
        <MetricCard label="Images"           value={metrics.imageCount} />
        <MetricCard label="Missing Alt Text" value={`${metrics.missingAltCount} (${altPct}%)`} colorClass={altColor} />
        <MetricCard label="Meta Title"       value={metrics.metaTitle ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaTitle ? 'good' : 'bad'} />
        <MetricCard label="Meta Description" value={metrics.metaDescription ? '✓ Present' : '✗ Missing'} colorClass={metrics.metaDescription ? 'good' : 'bad'} />
      </div>
      {metrics.ctaSamples?.length > 0 && (
        <div style={{ marginTop: 20 }}>
          <div style={{ fontFamily: 'var(--mono)', fontSize: '0.62rem', letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--text-dim)', marginBottom: 10, fontWeight: 600 }}>CTA Text Samples</div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            {metrics.ctaSamples.map((cta, i) => <span key={i} className="cta-pill">{cta}</span>)}
          </div>
        </div>
      )}
      {(metrics.metaTitle || metrics.metaDescription) && (
        <div className="serp-box">
          <div className="serp-label">SERP Preview</div>
          {metrics.metaTitle && <div className="serp-title">{metrics.metaTitle}</div>}
          {metrics.metaDescription && <div className="serp-desc">{metrics.metaDescription}</div>}
        </div>
      )}
    </Section>
  );
}

function InsightsDisplay({ ai }) {
  if (!ai) return null;
  const insights = [
    { label: 'SEO Structure',     text: ai.seoAnalysis },
    { label: 'Messaging Clarity', text: ai.messagingClarity },
    { label: 'CTA Analysis',      text: ai.ctaAnalysis },
    { label: 'Content Depth',     text: ai.contentDepth },
    { label: 'UX Concerns',       text: ai.uxConcerns },
  ].filter(i => i.text);
  return (
    <Section title="AI Insights" dotColor="orange" defaultOpen={true}>
      <div className="insights-grid">
        {insights.map((ins, i) => (
          <div className="insight-card" key={i}>
            <div className="insight-label">{ins.label}</div>
            <p>{ins.text}</p>
          </div>
        ))}
      </div>
    </Section>
  );
}

function Recommendations({ recommendations }) {
  if (!recommendations?.length) return null;
  const cls = p => ['p1','p2','p3','p4','p5'][p - 1] || 'p5';
  return (
    <Section title="Recommendations" dotColor="green" defaultOpen={true}>
      <div className="rec-list">
        {recommendations.map((rec, i) => (
          <div className="rec-card" key={i}>
            <div className={`rec-num ${cls(rec.priority)}`}>P{rec.priority}</div>
            <div>
              <div className="rec-title">{rec.title}</div>
              <div className="rec-reasoning">{rec.reasoning}</div>
              <div className="rec-action">→ {rec.action}</div>
            </div>
          </div>
        ))}
      </div>
    </Section>
  );
}

function PromptLogs({ promptLog }) {
  const [activeTab, setActiveTab] = useState('system');
  if (!promptLog) return null;
  const tabs = [
    { id: 'system', label: 'System Prompt', content: promptLog.systemPrompt },
    { id: 'user',   label: 'User Prompt',   content: promptLog.userPrompt },
    { id: 'input',  label: 'Input Data',    content: promptLog.inputData },
    { id: 'output', label: 'Raw Output',    content: promptLog.rawOutput },
  ];
  return (
    <Section title="Prompt Logs / Reasoning Trace" dotColor="red" defaultOpen={false}>
      <div className="log-chips">
        <div className="log-chip">Model: <span>{promptLog.model}</span></div>
        <div className="log-chip">~<span>{promptLog.inputTokensEstimate?.toLocaleString()}</span> tokens</div>
      </div>
      <div className="prompt-tabs">
        {tabs.map(t => (
          <button key={t.id} className={`prompt-tab ${activeTab === t.id ? 'active' : ''}`} onClick={() => setActiveTab(t.id)}>{t.label}</button>
        ))}
      </div>
      <pre className="prompt-code">{tabs.find(t => t.id === activeTab)?.content || '—'}</pre>
    </Section>
  );
}

export default function App() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const handleSubmit = async () => {
    if (!url.trim()) return;
    setLoading(true); setError(null); setResult(null);
    try {
      setResult(await auditWebsite(url.trim()));
    } catch (err) {
      setError(err.message || 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app-wrapper">

        {/* ── Dark hero ── */}
        <div className="hero-wrapper">
          <div className="hero-inner">

            <nav className="navbar">
              <div className="nav-logo">eight<span className="grad-text">25</span> audit</div>
              <div className="nav-badge">Internal Tool · AI-Powered</div>
            </nav>

            <div className="hero">
              <div className="hero-eyebrow">Website Intelligence</div>
              <h1>Audit any page.<br /><strong>Instantly.</strong></h1>
              <p className="hero-sub">Extract factual metrics and generate AI-powered insights grounded in real data — SEO, messaging, CTAs, UX, and prioritized recommendations.</p>
            </div>

            <div className="input-section">
              <div className="input-wrapper">
                <input
                  className="url-input"
                  type="text"
                  value={url}
                  onChange={e => setUrl(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleSubmit()}
                  placeholder="https://yourwebsite.com"
                  disabled={loading}
                  spellCheck={false}
                />
                <button className="audit-btn" onClick={handleSubmit} disabled={loading || !url.trim()}>
                  {loading ? 'Analysing...' : 'Run Audit →'}
                </button>
              </div>
              {error && <div className="error-msg">⚠ {error}</div>}
            </div>

          </div>
        </div>

        {/* ── White content area ── */}
        <div className="page-content">
          {loading && (
            <div className="loading">
              <div className="spinner" />
              <span>Scraping page · extracting metrics · generating AI insights…</span>
            </div>
          )}

          {result && (
            <>
              <div className="audit-meta">
                <div className="meta-dot" />
                <div className="meta-url">{result.url}</div>
                <div className="meta-time">Completed in {(result.processingTimeMs / 1000).toFixed(1)}s</div>
              </div>
              <MetricsDisplay metrics={result.metrics} />
              <InsightsDisplay ai={result.ai} />
              <Recommendations recommendations={result.ai?.recommendations} />
              <PromptLogs promptLog={result.promptLog} />
            </>
          )}
        </div>

      </div>
    </>
  );
}
